{
  "name": "Gemini Guided Tutor",
  "description": "A real-time guided learning platform that uses Gemini Live to see your screen and provide step-by-step audio guidance as you learn new skills.",
  "requestFramePermissions": [
    "camera",
    "microphone"
  ]
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface Transcription {
  id: string;
  role: 'user' | 'model';
  text: string;
  timestamp: number;
}

export enum SessionStatus {
  IDLE = 'idle',
  CONNECTING = 'connecting',
  ACTIVE = 'active',
  ERROR = 'error'
}

export interface AudioConfig {
  inputSampleRate: number;
  outputSampleRate: number;
}

export const MODEL_NAME = 'gemini-2.5-flash-native-audio-preview-12-2025';

export const SYSTEM_INSTRUCTION = `
You are a "Guided Learning Tutor". Your goal is to help users learn by observing their screen in real-time.
Rules:
1. Provide step-by-step guidance.
2. Observe the user's screen frames to see what they are doing.
3. Be encouraging, patient, and precise.
4. If they make a mistake, gently point it out and explain how to fix it.
5. Use concise audio responses suitable for a real-time conversation.
6. If the screen is black or nothing is shared, politely ask them to share their screen to begin the guided lesson.
`;

export const AUDIO_CONFIG = {
  inputSampleRate: 16000,
  outputSampleRate: 24000
};

export const FRAME_RATE = 1; // Frames per second
export const JPEG_QUALITY = 0.6;

export function encode(bytes: Uint8Array): string {
  let binary = '';
  const len = bytes.byteLength;
  for (let i = 0; i < len; i++) {
    binary += String.fromCharCode(bytes[i]);
  }
  return btoa(binary);
}

export function decode(base64: string): Uint8Array {
  const binaryString = atob(base64);
  const len = binaryString.length;
  const bytes = new Uint8Array(len);
  for (let i = 0; i < len; i++) {
    bytes[i] = binaryString.charCodeAt(i);
  }
  return bytes;
}

export async function decodeAudioData(
  data: Uint8Array,
  ctx: AudioContext,
  sampleRate: number,
  numChannels: number,
): Promise<AudioBuffer> {
  const dataInt16 = new Int16Array(data.buffer);
  const frameCount = dataInt16.length / numChannels;
  const buffer = ctx.createBuffer(numChannels, frameCount, sampleRate);

  for (let channel = 0; channel < numChannels; channel++) {
    const channelData = buffer.getChannelData(channel);
    for (let i = 0; i < frameCount; i++) {
      channelData[i] = dataInt16[i * numChannels + channel] / 32768.0;
    }
  }
  return buffer;
}

export function createBlob(data: Float32Array): { data: string; mimeType: string } {
  const l = data.length;
  const int16 = new Int16Array(l);
  for (let i = 0; i < l; i++) {
    int16[i] = data[i] * 32768;
  }
  return {
    data: encode(new Uint8Array(int16.buffer)),
    mimeType: 'audio/pcm;rate=16000',
  };
}

import React, { useState, useRef, useCallback, useEffect } from 'react';
import { GoogleGenAI, Modality, LiveServerMessage } from '@google/genai';
import { Header } from './components/Header';
import { TranscriptionList } from './components/TranscriptionList';
import { ScreenShare } from './components/ScreenShare';
import { ControlPanel } from './components/ControlPanel';
import { 
  MODEL_NAME, 
  SYSTEM_INSTRUCTION, 
  AUDIO_CONFIG, 
  FRAME_RATE, 
  JPEG_QUALITY 
} from './constants';
import { SessionStatus, Transcription } from './types';
import { 
  decode, 
  decodeAudioData, 
  createBlob, 
  encode 
} from './services/audioUtils';

const App: React.FC = () => {
  const [status, setStatus] = useState<SessionStatus>(SessionStatus.IDLE);
  const [transcriptions, setTranscriptions] = useState<Transcription[]>([]);
  const [isMuted, setIsMuted] = useState(false);
  const [isScreenSharing, setIsScreenSharing] = useState(false);

  const aiRef = useRef<any>(null);
  const sessionRef = useRef<any>(null);
  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);

  const inputAudioCtxRef = useRef<AudioContext | null>(null);
  const outputAudioCtxRef = useRef<AudioContext | null>(null);
  const nextStartTimeRef = useRef<number>(0);
  const audioSourcesRef = useRef<Set<AudioBufferSourceNode>>(new Set());

  const currentInputText = useRef('');
  const currentOutputText = useRef('');

  const stopSession = useCallback(() => {
    if (sessionRef.current) {
      sessionRef.current.close();
      sessionRef.current = null;
    }

    audioSourcesRef.current.forEach(source => source.stop());
    audioSourcesRef.current.clear();

    if (inputAudioCtxRef.current) {
      inputAudioCtxRef.current.close();
      inputAudioCtxRef.current = null;
    }
    if (outputAudioCtxRef.current) {
      outputAudioCtxRef.current.close();
      outputAudioCtxRef.current = null;
    }

    setIsScreenSharing(false);
    setStatus(SessionStatus.IDLE);
  }, []);

  const handleMessage = async (message: LiveServerMessage) => {
    // 1. Audio Playback
    const audioData = message.serverContent?.modelTurn?.parts[0]?.inlineData?.data;
    if (audioData && outputAudioCtxRef.current) {
      const ctx = outputAudioCtxRef.current;
      nextStartTimeRef.current = Math.max(nextStartTimeRef.current, ctx.currentTime);

      const buffer = await decodeAudioData(
        decode(audioData),
        ctx,
        AUDIO_CONFIG.outputSampleRate,
        1
      );

      const source = ctx.createBufferSource();
      source.buffer = buffer;
      source.connect(ctx.destination);
      source.onended = () => audioSourcesRef.current.delete(source);

      source.start(nextStartTimeRef.current);
      nextStartTimeRef.current += buffer.duration;
      audioSourcesRef.current.add(source);
    }

    // 2. Transcription Logic
    if (message.serverContent?.inputTranscription) {
      currentInputText.current += message.serverContent.inputTranscription.text;
    }
    if (message.serverContent?.outputTranscription) {
      currentOutputText.current += message.serverContent.outputTranscription.text;
    }

    if (message.serverContent?.turnComplete) {
      if (currentInputText.current.trim()) {
        setTranscriptions(prev => [
          ...prev, 
          { id: Date.now().toString(), role: 'user', text: currentInputText.current, timestamp: Date.now() }
        ]);
      }
      if (currentOutputText.current.trim()) {
        setTranscriptions(prev => [
          ...prev, 
          { id: (Date.now() + 1).toString(), role: 'model', text: currentOutputText.current, timestamp: Date.now() }
        ]);
      }
      currentInputText.current = '';
      currentOutputText.current = '';
    }

    // 3. Interruption Handling
    if (message.serverContent?.interrupted) {
      audioSourcesRef.current.forEach(s => {
        try { s.stop(); } catch (e) {}
      });
      audioSourcesRef.current.clear();
      nextStartTimeRef.current = 0;
    }
  };

  const startSession = async () => {
    try {
      setStatus(SessionStatus.CONNECTING);

      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });
      aiRef.current = ai;

      const inputCtx = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: AUDIO_CONFIG.inputSampleRate });
      const outputCtx = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: AUDIO_CONFIG.outputSampleRate });
      inputAudioCtxRef.current = inputCtx;
      outputAudioCtxRef.current = outputCtx;

      const micStream = await navigator.mediaDevices.getUserMedia({ audio: true });

      const sessionPromise = ai.live.connect({
        model: MODEL_NAME,
        config: {
          responseModalities: [Modality.AUDIO],
          systemInstruction: SYSTEM_INSTRUCTION,
          speechConfig: {
            voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Puck' } }
          },
          inputAudioTranscription: {},
          outputAudioTranscription: {}
        },
        callbacks: {
          onopen: () => {
            console.log('Session opened');
            setStatus(SessionStatus.ACTIVE);

            // Microphone Streaming
            const source = inputCtx.createMediaStreamSource(micStream);
            const processor = inputCtx.createScriptProcessor(4096, 1, 1);

            processor.onaudioprocess = (e) => {
              if (isMuted) return;
              const inputData = e.inputBuffer.getChannelData(0);
              const pcmBlob = createBlob(inputData);
              sessionRef.current?.sendRealtimeInput({ media: pcmBlob });
            };

            source.connect(processor);
            processor.connect(inputCtx.destination);
          },
          onmessage: handleMessage,
          onerror: (err) => {
            console.error('Session error:', err);
            setStatus(SessionStatus.ERROR);
          },
          onclose: () => {
            console.log('Session closed');
            stopSession();
          }
        }
      });

      sessionRef.current = await sessionPromise;

    } catch (err) {
      console.error('Failed to start session:', err);
      setStatus(SessionStatus.ERROR);
    }
  };

  const toggleScreenShare = async () => {
    if (isScreenSharing) {
      if (videoRef.current?.srcObject) {
        const tracks = (videoRef.current.srcObject as MediaStream).getTracks();
        tracks.forEach(track => track.stop());
        videoRef.current.srcObject = null;
      }
      setIsScreenSharing(false);
      return;
    }

    try {
      const screenStream = await navigator.mediaDevices.getDisplayMedia({
        video: { cursor: 'always' } as any,
        audio: false
      });

      if (videoRef.current) {
        videoRef.current.srcObject = screenStream;
        setIsScreenSharing(true);
      }

      screenStream.getVideoTracks()[0].onended = () => {
        setIsScreenSharing(false);
      };

    } catch (err) {
      console.error('Screen share error:', err);
    }
  };

  // Frame streaming effect
  useEffect(() => {
    let interval: number | undefined;
    if (isScreenSharing && status === SessionStatus.ACTIVE) {
      interval = window.setInterval(() => {
        if (!videoRef.current || !canvasRef.current || !sessionRef.current) return;

        const video = videoRef.current;
        const canvas = canvasRef.current;
        const ctx = canvas.getContext('2d');

        if (ctx && video.videoWidth > 0) {
          canvas.width = video.videoWidth;
          canvas.height = video.videoHeight;
          ctx.drawImage(video, 0, 0, canvas.width, canvas.height);

          canvas.toBlob((blob) => {
            if (blob) {
              const reader = new FileReader();
              reader.onloadend = () => {
                const base64 = (reader.result as string).split(',')[1];
                sessionRef.current?.sendRealtimeInput({
                  media: { data: base64, mimeType: 'image/jpeg' }
                });
              };
              reader.readAsDataURL(blob);
            }
          }, 'image/jpeg', JPEG_QUALITY);
        }
      }, 1000 / FRAME_RATE);
    }
    return () => clearInterval(interval);
  }, [isScreenSharing, status]);

  return (
    <div className="flex flex-col h-screen bg-slate-950 text-slate-200 overflow-hidden">
      <Header status={status} />

      <main className="flex-1 flex flex-col md:flex-row overflow-hidden p-4 gap-4">
        {/* Left Side: Screen & Visuals */}
        <div className="flex-1 flex flex-col gap-4 overflow-hidden">
          <ScreenShare 
            videoRef={videoRef} 
            isSharing={isScreenSharing} 
            onToggle={toggleScreenShare} 
          />
          <div className="hidden">
            <canvas ref={canvasRef} />
          </div>
        </div>

        {/* Right Side: Transcription & Chat History */}
        <div className="w-full md:w-96 flex flex-col gap-4 overflow-hidden">
          <TranscriptionList transcriptions={transcriptions} status={status} />
        </div>
      </main>

      <ControlPanel 
        status={status}
        isMuted={isMuted}
        onToggleMute={() => setIsMuted(!isMuted)}
        onStart={startSession}
        onStop={stopSession}
        onToggleScreen={toggleScreenShare}
        isScreenSharing={isScreenSharing}
      />
    </div>
  );
};

export default App;

import React from 'react';
import { SessionStatus } from '../types';

interface HeaderProps {
  status: SessionStatus;
}

export const Header: React.FC<HeaderProps> = ({ status }) => {
  const getStatusColor = () => {
    switch (status) {
      case SessionStatus.ACTIVE: return 'bg-emerald-500';
      case SessionStatus.CONNECTING: return 'bg-amber-500';
      case SessionStatus.ERROR: return 'bg-rose-500';
      default: return 'bg-slate-500';
    }
  };

  const getStatusText = () => {
    switch (status) {
      case SessionStatus.ACTIVE: return 'Live Guidance Active';
      case SessionStatus.CONNECTING: return 'Establishing Link...';
      case SessionStatus.ERROR: return 'Connection Error';
      default: return 'Tutor Offline';
    }
  };

  return (
    <header className="px-6 py-4 border-b border-slate-800 flex justify-between items-center bg-slate-900/50 backdrop-blur-md">
      <div className="flex items-center gap-3">
        <div className="w-10 h-10 bg-indigo-600 rounded-xl flex items-center justify-center shadow-lg shadow-indigo-500/20">
          <svg className="w-6 h-6 text-white" fill="none" viewBox="0 0 24 24" stroke="currentColor">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 6.253v13m0-13C10.832 5.477 9.246 5 7.5 5S4.168 5.477 3 6.253v13C4.168 18.477 5.754 18 7.5 18s3.332.477 4.5 1.253m0-13C13.168 5.477 14.754 5 16.5 5c1.747 0 3.332.477 4.5 1.253v13C19.832 18.477 18.247 18 16.5 18c-1.746 0-3.332.477-4.5 1.253" />
          </svg>
        </div>
        <div>
          <h1 className="text-xl font-bold tracking-tight text-white">Gemini Guided Tutor</h1>
          <p className="text-xs text-slate-400 font-medium">Real-time Visual Intelligence</p>
        </div>
      </div>

      <div className="flex items-center gap-2 bg-slate-800/50 px-3 py-1.5 rounded-full border border-slate-700/50">
        <div className={`w-2 h-2 rounded-full ${getStatusColor()} animate-pulse`} />
        <span className="text-xs font-semibold text-slate-300 uppercase tracking-wider">
          {getStatusText()}
        </span>
      </div>
    </header>
  );
};

import React from 'react';

interface ScreenShareProps {
  videoRef: React.RefObject<HTMLVideoElement>;
  isSharing: boolean;
  onToggle: () => void;
}

