    <div className="relative flex-1 bg-slate-900 rounded-2xl border border-slate-800 overflow-hidden shadow-2xl group">
      <video 
        ref={videoRef} 
        autoPlay 
        playsInline 
        className={`w-full h-full object-contain ${isSharing ? 'opacity-100' : 'opacity-0'}`} 
      />

      {!isSharing && (
        <div className="absolute inset-0 flex flex-col items-center justify-center text-slate-500 p-8 text-center">
          <div className="w-20 h-20 bg-slate-800 rounded-full flex items-center justify-center mb-6 group-hover:scale-110 transition-transform duration-300">
            <svg className="w-10 h-10" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1.5} d="M9.75 17L9 20l-1 1h8l-1-1-.75-3M3 13h18M5 17h14a2 2 0 002-2V5a2 2 0 00-2-2H5a2 2 0 00-2 2v10a2 2 0 002 2z" />
            </svg>
          </div>
          <h3 className="text-xl font-semibold text-slate-300 mb-2">Ready to Start Learning?</h3>
          <p className="max-w-xs text-sm">
            Share your screen so your AI tutor can see what you're working on and provide real-time guidance.
          </p>
          <button 
            onClick={onToggle}
            className="mt-8 px-6 py-3 bg-indigo-600 hover:bg-indigo-500 text-white rounded-xl font-semibold transition-all shadow-lg shadow-indigo-500/20 active:scale-95"
          >
            Share Screen
          </button>
        </div>
      )}

      {isSharing && (
        <div className="absolute top-4 right-4 flex gap-2">
          <div className="bg-rose-500/90 text-white px-3 py-1 rounded-md text-[10px] font-bold uppercase tracking-widest backdrop-blur-sm">
            Live Stream
          </div>
          <button 
            onClick={onToggle}
            className="bg-slate-800/90 hover:bg-rose-600/90 text-white p-1.5 rounded-md backdrop-blur-sm transition-colors"
            title="Stop Sharing"
          >
            <svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" />
            </svg>
          </button>
        </div>
      )}
    </div>
  );
};

import React, { useEffect, useRef } from 'react';
import { Transcription, SessionStatus } from '../types';

interface TranscriptionListProps {
  transcriptions: Transcription[];
  status: SessionStatus;
}

export const TranscriptionList: React.FC<TranscriptionListProps> = ({ transcriptions, status }) => {
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [transcriptions]);

  return (
    <div className="flex flex-col h-full bg-slate-900/50 rounded-2xl border border-slate-800 overflow-hidden">
      <div className="p-4 border-b border-slate-800 bg-slate-900/80 flex items-center justify-between">
        <h2 className="text-sm font-bold text-slate-400 uppercase tracking-widest">Conversation</h2>
        <span className="text-[10px] px-2 py-0.5 bg-slate-800 rounded text-slate-500 font-mono">
          {transcriptions.length} Messages
        </span>
      </div>

      <div 
        ref={scrollRef}
        className="flex-1 overflow-y-auto p-4 space-y-4 scroll-smooth"
      >
        {transcriptions.length === 0 && status === SessionStatus.ACTIVE && (
          <div className="h-full flex flex-col items-center justify-center text-slate-500 italic text-sm">
            <p>Start speaking or performing a task...</p>
          </div>
        )}

        {transcriptions.length === 0 && status !== SessionStatus.ACTIVE && (
          <div className="h-full flex flex-col items-center justify-center text-slate-600 text-center px-4">
            <svg className="w-8 h-8 mb-3 opacity-20" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1.5} d="M8 12h.01M12 12h.01M16 12h.01M21 12c0 4.418-4.03 8-9 8a9.863 9.863 0 01-4.255-.949L3 20l1.395-3.72C3.512 15.042 3 13.574 3 12c0-4.418 4.03-8 9-8s9 3.582 9 8z" />
            </svg>
            <p className="text-xs">Dialogue transcriptions will appear here once the session starts.</p>
          </div>
        )}

        {transcriptions.map((t) => (
          <div 
            key={t.id} 
            className={`flex flex-col ${t.role === 'user' ? 'items-end' : 'items-start'}`}
          >
            <div 
              className={`max-w-[85%] rounded-2xl px-4 py-2.5 text-sm shadow-sm ${
                t.role === 'user' 
                  ? 'bg-indigo-600 text-white rounded-br-none' 
                  : 'bg-slate-800 text-slate-200 border border-slate-700/50 rounded-bl-none'
              }`}
            >
              <div className="text-[10px] opacity-60 mb-1 font-bold uppercase">
                {t.role === 'user' ? 'You' : 'AI Tutor'}
              </div>
              <p className="leading-relaxed">{t.text}</p>
            </div>
            <span className="text-[10px] text-slate-600 mt-1 px-1">
              {new Date(t.timestamp).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
            </span>
          </div>
        ))}
      </div>
    </div>
  );
};

import React from 'react';
import { SessionStatus } from '../types';

interface ControlPanelProps {
  status: SessionStatus;
  isMuted: boolean;
  onToggleMute: () => void;
  onStart: () => void;
  onStop: () => void;
  onToggleScreen: () => void;
  isScreenSharing: boolean;
}

export const ControlPanel: React.FC<ControlPanelProps> = ({
  status,
  isMuted,
  onToggleMute,
  onStart,
  onStop,
  onToggleScreen,
  isScreenSharing
}) => {
  const isActive = status === SessionStatus.ACTIVE;
  const isConnecting = status === SessionStatus.CONNECTING;

  return (
    <div className="fixed bottom-8 left-1/2 -translate-x-1/2 flex items-center gap-4 bg-slate-900/80 backdrop-blur-xl border border-slate-700/50 px-6 py-4 rounded-3xl shadow-2xl z-50">
      {/* Mic Button */}
      <button
        onClick={onToggleMute}
        disabled={!isActive}
        className={`p-4 rounded-2xl transition-all ${
          isMuted 
            ? 'bg-rose-500/20 text-rose-500' 
            : 'bg-slate-800 text-slate-300 hover:bg-slate-700 disabled:opacity-50'
        }`}
        title={isMuted ? "Unmute Microphone" : "Mute Microphone"}
      >
        {isMuted ? (
          <svg className="w-6 h-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 11a7 7 0 01-7 7m0 0a7 7 0 01-7-7m7 7v4m0 0H8m4 0h4m-4-8a3 3 0 01-3-3V5a3 3 0 116 0v6a3 3 0 01-3 3z" />
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M1 1l22 22" />
          </svg>
        ) : (
          <svg className="w-6 h-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 11a7 7 0 01-7 7m0 0a7 7 0 01-7-7m7 7v4m0 0H8m4 0h4m-4-8a3 3 0 01-3-3V5a3 3 0 116 0v6a3 3 0 01-3 3z" />
          </svg>
        )}
      </button>

      {/* Main Start/Stop Button */}
      {isActive ? (
        <button
          onClick={onStop}
          className="px-8 py-4 bg-rose-600 hover:bg-rose-500 text-white rounded-2xl font-bold transition-all flex items-center gap-3 shadow-lg shadow-rose-500/20 active:scale-95"
        >
          <div className="w-2 h-2 bg-white rounded-full animate-pulse" />
          Stop Session
        </button>
      ) : (
        <button
          onClick={onStart}
          disabled={isConnecting}
          className="px-8 py-4 bg-indigo-600 hover:bg-indigo-500 disabled:bg-slate-700 text-white rounded-2xl font-bold transition-all flex items-center gap-3 shadow-lg shadow-indigo-500/20 active:scale-95"
        >
          {isConnecting ? (
            <>
              <svg className="animate-spin h-5 w-5 text-white" fill="none" viewBox="0 0 24 24">
                <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
                <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
              </svg>
              Connecting...
            </>
          ) : (
            <>
              <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M14.752 11.168l-3.197-2.132A1 1 0 0010 9.87v4.263a1 1 0 001.555.832l3.197-2.132a1 1 0 000-1.664z" />
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M21 12a9 9 0 11-18 0 9 9 0 0118 0z" />
              </svg>
              Start Lesson
            </>
          )}
        </button>
      )}

      {/* Screen Share Toggle */}
      <button
        onClick={onToggleScreen}
        className={`p-4 rounded-2xl transition-all ${
          isScreenSharing 
            ? 'bg-indigo-600/20 text-indigo-400 border border-indigo-500/30' 
            : 'bg-slate-800 text-slate-300 hover:bg-slate-700'
        }`}
        title={isScreenSharing ? "Stop Screen Share" : "Start Screen Share"}
